#include<bits/stdc++.h>
using namespace std;
const long long N=2e7+5;
struct FHQ_Treap
{
    struct node
    {
        long long l,r;
        long long val,key;
        long long siz,sum;
        long long tag;
    }t[N];
    long long root[N],tot,cnt;
    long long newnode(long long v)
    {
        t[++tot].val=v;
        t[tot].key=rand();
        t[tot].siz=1;
        t[tot].sum=v;
        return tot;
    }
    long long copynode(long long v)
    {
        t[++tot]=t[v];
        return tot;
    }
    void pushup(long long x)
    {
        t[x].siz=t[t[x].l].siz+t[t[x].r].siz+1;
        t[x].sum=t[t[x].l].sum+t[t[x].r].sum+t[x].val;
    }
    void pushdown(long long x)
    {
        if(t[x].tag)
        {
            if(t[x].l)
            {
                t[x].l=copynode(t[x].l);
            }
            if(t[x].r)
            {
                t[x].r=copynode(t[x].r);
            }
            swap(t[x].l,t[x].r);
            t[t[x].l].tag^=1;
            t[t[x].r].tag^=1;
            t[x].tag=0;
        }
    }
    void split(long long p,long long v,long long &x,long long &y)
    {
        if(p==0)
        {
            x=y=0;
            return;
        }
        pushdown(p);
        if(t[t[p].l].siz+1<=v)
        {
            x=copynode(p);
            split(t[x].r,v-t[t[p].l].siz-1,t[x].r,y);
            pushup(x);
        }
        else
        {
            y=copynode(p);
            split(t[y].l,v,x,t[y].l);
            pushup(y);
        }
    }
    long long merge(long long x,long long y)
    {
        if(x==0||y==0)
        {
            return x+y;
        }
        pushdown(x);
        pushdown(y);
        if(t[x].key<t[y].key)
        {
            t[x].r=merge(t[x].r,y);
            pushup(x);
            return x;
        }
        else
        {
            t[y].l=merge(x,t[y].l);
            pushup(y);
            return y;
        }
    }
    long long copyver(long long v)
    {
        root[++cnt]=root[v];
        return cnt;
    }
    void insert(long long ver,long long p,long long v)
    {
        long long x,y;
        split(root[ver],p,x,y);
        root[ver]=merge(merge(x,newnode(v)),y);
    }
    void del(long long ver,long long v)
    {
        long long x,y,z;
        split(root[ver],v,x,z);
        split(x,v-1,x,y);
        root[ver]=merge(x,z);
    }
    void reverse(long long ver,long long l,long long r)
    {
        long long x,y,z;
        split(root[ver],r,x,z);
        split(x,l-1,x,y);
        t[y].tag^=1;
        root[ver]=merge(merge(x,y),z);
    }
    long long getsum(long long ver,long long l,long long r)
    {
        long long x,y,z;
        split(root[ver],r,x,z);
        split(x,l-1,x,y);
        long long ans=t[y].sum;
        root[ver]=merge(merge(x,y),z);
        return ans;
    }
}t;
int main()
{
    long long m;
    scanf("%lld",&m);
    long long lstans=0;
    while(m--)
    {
        long long op,v,l,r,p,x;
        scanf("%lld%lld",&v,&op);
        long long now=t.copyver(v);
        if(op==1)
        {
            scanf("%lld%lld",&p,&x);
            p^=lstans;
            x^=lstans;
            t.insert(now,p,x);
        }
        else if(op==2)
        {
            scanf("%lld",&p);
            p^=lstans;
            t.del(now,p);
        }
        else if(op==3)
        {
            scanf("%lld%lld",&l,&r);
            l^=lstans;
            r^=lstans;
            t.reverse(now,l,r);
        }
        else
        {
            scanf("%lld%lld",&l,&r);
            l^=lstans;
            r^=lstans;
            printf("%lld\n",lstans=t.getsum(now,l,r));
        }
    }
    return 0;
}
